        new Recipe { Id = 4, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef\nTaco seasoning\nCorn tortillas\nLettuce\nTomato\nCheddar cheese\nSour cream\nSalsa", Steps = "1. Brown ground beef in a skillet.\n2. Add taco seasoning and water, simmer 5 minutes.\n3. Warm tortillas in a dry pan.\n4. Assemble tacos with beef and toppings.\n5. Serve with salsa and sour cream.", AverageRating = 4.2, RatingCount = 9 },
        new Recipe { Id = 5, Title = "Pad Thai", Category = "Thai", Ingredients = "Rice noodles\nShrimp or tofu\nEggs\nBean sprouts\nGreen onions\nPeanuts\nTamarind paste\nFish sauce\nSugar\nLime", Steps = "1. Soak rice noodles in warm water 30 minutes.\n2. Make sauce: mix tamarind paste, fish sauce, and sugar.\n3. Stir-fry shrimp/tofu until cooked, set aside.\n4. Scramble eggs in the same pan.\n5. Add noodles and sauce, toss until coated.\n6. Add protein, bean sprouts, and green onions.\n7. Serve with crushed peanuts and lime wedge.", AverageRating = 4.6, RatingCount = 15 },
        new Recipe { Id = 6, Title = "Guacamole", Category = "Mexican", Ingredients = "Avocados\nLime juice\nRed onion\nCilantro\nJalapeño\nTomato\nSalt\nGarlic", Steps = "1. Halve avocados and remove pits.\n2. Mash avocado to desired consistency.\n3. Stir in diced onion, tomato, and jalapeño.\n4. Add lime juice, cilantro, garlic, and salt.\n5. Taste and adjust seasoning.\n6. Serve immediately with tortilla chips.", AverageRating = 4.4, RatingCount = 20 },
        new Recipe { Id = 7, Title = "Miso Soup", Category = "Japanese", Ingredients = "Dashi stock\nMiso paste\nTofu\nWakame seaweed\nGreen onions", Steps = "1. Bring dashi stock to a gentle simmer.\n2. Rehydrate wakame in water for 5 minutes.\n3. Dissolve miso paste in a ladle of warm broth.\n4. Add miso mixture back to pot (do not boil).\n5. Add cubed tofu and wakame.\n6. Serve topped with sliced green onions.", AverageRating = 4.1, RatingCount = 7 },
        new Recipe { Id = 8, Title = "Chocolate Chip Cookies", Category = "Desserts", Ingredients = "Butter\nSugar\nBrown sugar\nEggs\nVanilla extract\nFlour\nBaking soda\nSalt\nChocolate chips", Steps = "1. Cream butter and sugars until fluffy.\n2. Beat in eggs and vanilla.\n3. Mix flour, baking soda, and salt separately.\n4. Combine wet and dry ingredients.\n5. Fold in chocolate chips.\n6. Scoop onto baking sheets.\n7. Bake at 375°F (190°C) for 9-11 minutes.", AverageRating = 4.9, RatingCount = 31 },
    };

    private readonly Dictionary<int, List<int>> _ratings = new();

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
    }

    public IReadOnlyList<Recipe> GetRecipesByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetRecipe(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int stars)
    {
        if (stars < 1 || stars > 5) return;

        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is null) return;

        if (!_ratings.ContainsKey(recipeId))
            _ratings[recipeId] = new List<int>();

        _ratings[recipeId].Add(stars);

        var allRatings = _ratings[recipeId];
        recipe.AverageRating = Math.Round(allRatings.Average(), 1);
        recipe.RatingCount = allRatings.Count + recipe.RatingCount;
    }

    public void SubmitRecipe(RecipeSubmission submission)
    {
        var newId = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(new Recipe
        {
            Id = newId,
            Title = submission.Title,
            Category = submission.Category,
            Ingredients = submission.Ingredients,
            Steps = submission.Steps,
            AverageRating = 0,
            RatingCount = 0
        });
    }
}
