@page "/recipes"
@page "/recipes/{Category}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>Browse Recipes</PageTitle>

@if (string.IsNullOrEmpty(Category))
{
    <h1>All Categories</h1>
    <ul class="list-group">
        @foreach (var cat in RecipeService.GetCategories())
        {
            <li class="list-group-item">
                <a href="recipes/@cat">@cat</a>
            </li>
        }
    </ul>
}
else
{
    <h1>@Category Recipes</h1>
    <a href="recipes" class="btn btn-outline-secondary mb-3">← All Categories</a>

    <div class="row">
        @foreach (var recipe in RecipeService.GetRecipesByCategory(Category))
        {
            <div class="col-md-6 mb-3">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">
                            ⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)
                        </p>
                        <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string? Category { get; set; }
}

@page "/recipe/{Id:int}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe")</PageTitle>

@if (recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>The recipe you're looking for doesn't exist.</p>
    <a href="recipes" class="btn btn-primary">Browse Recipes</a>
}
else
{
    <a href="recipes/@recipe.Category" class="btn btn-outline-secondary mb-3">← Back to @recipe.Category</a>

    <h1>@recipe.Title</h1>
    <span class="badge bg-secondary mb-3">@recipe.Category</span>

    <StarRating RecipeId="recipe.Id" CurrentRating="recipe.AverageRating" RatingCount="recipe.RatingCount" />

    <h3 class="mt-4">Ingredients</h3>
    <ul class="list-group mb-4">
        @foreach (var ingredient in recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            <li class="list-group-item">@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol class="list-group list-group-numbered mb-4">
        @foreach (var step in recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            var text = step.TrimStart();
            if (text.Length > 2 && text[0] >= '0' && text[0] <= '9' && text[1] == '.')
                text = text[2..].TrimStart();
            <li class="list-group-item">@text</li>
        }
    </ol>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private RecipeShare.Models.Recipe? recipe;

    protected override void OnInitialized()
    {
        recipe = RecipeService.GetRecipe(Id);
    }
}

@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService

<div class="my-3">
    <span class="me-2">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= displayRating ? "star-filled" : "star-empty")"
              @onclick="() => Rate(star)"
              @onmouseover="() => Hover(star)"
              @onmouseout="ResetHover"
              role="button"
              title="@star star(s)">
            @(star <= displayRating ? "★" : "☆")
        </span>
    }
    <span class="ms-3 text-muted">
        ⭐ @CurrentRating.ToString("F1") (@RatingCount ratings)
    </span>
    @if (submitted)
    {
        <span class="ms-2 text-success">✓ Thanks for rating!</span>
    }
</div>

<style>
    .star {
        font-size: 1.5rem;
        cursor: pointer;
        transition: color 0.15s;
    }
    .star-filled {
        color: #ffc107;
    }
    .star-empty {
        color: #dee2e6;
    }
    .star:hover {
        transform: scale(1.2);
    }
</style>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentRating { get; set; }
    [Parameter] public int RatingCount { get; set; }

    private int hoverRating;
    private int selectedRating;
    private bool submitted;

    private int displayRating => hoverRating > 0 ? hoverRating : selectedRating;

    private void Hover(int star) => hoverRating = star;
    private void ResetHover() => hoverRating = 0;

    private void Rate(int star)
    {
        selectedRating = star;
        RecipeService.AddRating(RecipeId, star);
        var recipe = RecipeService.GetRecipe(RecipeId);
        if (recipe is not null)
        {
            CurrentRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
        submitted = true;
    }
}

@page "/submit"
@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>Submit a Recipe</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>🎉 Recipe Submitted!</h4>
        <p>Your recipe "<strong>@model.Title</strong>" has been added to the collection.</p>
        <a href="recipes/@model.Category" class="btn btn-primary">View in @model.Category</a>
        <button class="btn btn-outline-secondary ms-2" @onclick="Reset">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="recipeForm">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="model.Title" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => model.Title" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="model.Category">
                <option value="">-- Select a category --</option>
                <option value="Italian">Italian</option>
                <option value="Indian">Indian</option>
                <option value="Mexican">Mexican</option>
                <option value="Thai">Thai</option>
                <option value="Japanese">Japanese</option>
                <option value="Desserts">Desserts</option>
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="() => model.Category" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="model.Ingredients"
                placeholder="1 cup flour&#10;2 eggs&#10;1/2 cup sugar" />
            <ValidationMessage For="() => model.Ingredients" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="model.Steps"
                placeholder="1. Preheat oven to 350°F&#10;2. Mix dry ingredients&#10;3. Add wet ingredients" />
            <ValidationMessage For="() => model.Steps" />
        </div>

        <button type="submit" class="btn btn-success" disabled="@(!IsValid)">
            Submit Recipe
        </button>
    </EditForm>
}

@code {
    private RecipeShare.Models.RecipeSubmission model = new();
    private bool submitted;

    private bool IsValid =>
        !string.IsNullOrWhiteSpace(model.Title) &&
        !string.IsNullOrWhiteSpace(model.Category) &&
        !string.IsNullOrWhiteSpace(model.Ingredients) &&
        !string.IsNullOrWhiteSpace(model.Steps);

